import { describe, expect, it } from "vitest";
import { parseQuery } from "../src/parseQuery.js";

describe("parseQuery", () => {
  // --- Basic mapping ---

  // Bug: fails to parse a simple pair at all / returns wrong container type.
  it("maps a single key to its string value", () => {
    expect(parseQuery("a=1")).toEqual({ a: "1" });
  });

  // Bug: value stored as a number or otherwise not a plain string.
  it("keeps values as strings, not numbers", () => {
    const result = parseQuery("n=42");
    expect(result.n).toBe("42");
  });

  // Bug: empty input mishandled — a lone "" segment must NOT create a key.
  it("returns an empty object for an empty string", () => {
    expect(parseQuery("")).toEqual({});
  });

  // --- Leading "?" handling ---

  // Bug: leading "?" not stripped, producing a "?a" key.
  it("strips a single leading '?'", () => {
    expect(parseQuery("?a=1")).toEqual({ a: "1" });
  });

  // Bug: "?" stripped even when it is not leading, corrupting the first key.
  it("does not strip '?' when it is not the leading character", () => {
    expect(parseQuery("a=1")).toEqual({ a: "1" });
    // A "?" only counts if it starts the string; here it is part of a value.
    expect(parseQuery("a=?")).toEqual({ a: "?" });
  });

  // --- Segment separation & empty segments ---

  // Bug: empty segment from "&&" creates a spurious "" key.
  it("skips empty segments between '&' separators", () => {
    expect(parseQuery("a=1&&b=2")).toEqual({ a: "1", b: "2" });
  });

  // Bug: leading/trailing "&" creates spurious empty keys.
  it("skips leading and trailing empty segments", () => {
    expect(parseQuery("&a=1&")).toEqual({ a: "1" });
  });

  // Bug: two pairs collapsed or second pair dropped.
  it("parses multiple distinct keys", () => {
    expect(parseQuery("a=1&b=2")).toEqual({ a: "1", b: "2" });
  });

  // --- Repeated keys become arrays, in order ---

  // Bug: duplicate key overwrites instead of collecting into an array.
  it("collects a key seen twice into an array in order of appearance", () => {
    expect(parseQuery("a=1&a=2")).toEqual({ a: ["1", "2"] });
  });

  // Bug: third+ occurrence replaces the array or is dropped (off-by-one on
  // the array-vs-scalar branch).
  it("appends the third occurrence to the existing array in order", () => {
    expect(parseQuery("a=1&a=2&a=3")).toEqual({ a: ["1", "2", "3"] });
  });

  // Bug: order reversed when building the array.
  it("preserves appearance order, not sorted order", () => {
    expect(parseQuery("a=z&a=a")).toEqual({ a: ["z", "a"] });
  });

  // Bug: a single occurrence wrongly wrapped in an array.
  it("does not wrap a single occurrence in an array", () => {
    expect(Array.isArray(parseQuery("a=1").a)).toBe(false);
  });

  // --- Bare keys (no "=") ---

  // Bug: bare key dropped or mapped to something other than "".
  it("maps a bare key with no '=' to an empty string", () => {
    expect(parseQuery("flag")).toEqual({ flag: "" });
  });

  // Bug: bare key not treated as a value when combining with a real value.
  it("treats a bare key as the empty-string value inside a duplicate array", () => {
    expect(parseQuery("a&a=2")).toEqual({ a: ["", "2"] });
  });

  // Bug: "a=" (present '=' but empty value) confused with a bare key or dropped.
  it("maps a key with a trailing '=' and no value to an empty string", () => {
    expect(parseQuery("a=")).toEqual({ a: "" });
  });

  // --- Splitting on the first "=" only ---

  // Bug: split on every "=" (e.g. via split("=")) truncates the value.
  it("splits only on the first '=', keeping later '=' in the value", () => {
    expect(parseQuery("a=b=c")).toEqual({ a: "b=c" });
  });

  // Bug: empty key from a leading "=" mishandled.
  it("allows an empty key when the segment starts with '='", () => {
    expect(parseQuery("=1")).toEqual({ "": "1" });
  });

  // --- "+" decodes to space ---

  // Bug: "+" left literal in values.
  it("decodes '+' to a space in values", () => {
    expect(parseQuery("a=b+c")).toEqual({ a: "b c" });
  });

  // Bug: "+" handled only in values, not keys.
  it("decodes '+' to a space in keys", () => {
    expect(parseQuery("a+b=c")).toEqual({ "a b": "c" });
  });

  // --- Percent-decoding ---

  // Bug: values not percent-decoded.
  it("percent-decodes values", () => {
    expect(parseQuery("a=%20")).toEqual({ a: " " });
  });

  // Bug: keys not percent-decoded (so "%61" stays literal instead of "a").
  it("percent-decodes keys", () => {
    expect(parseQuery("%61=1")).toEqual({ a: "1" });
  });

  // Bug: multi-byte UTF-8 sequences not decoded correctly.
  it("percent-decodes multi-byte UTF-8 sequences", () => {
    expect(parseQuery("x=%E2%9C%93")).toEqual({ x: "✓" });
  });

  // Bug: "+" replacement and percent-decoding applied in the wrong order.
  // "%2B" must decode to a literal "+", NOT be turned into a space; while a
  // literal "+" in the same token must become a space.
  it("replaces '+' with space BEFORE percent-decoding, so %2B stays '+'", () => {
    expect(parseQuery("a=%2B+x")).toEqual({ a: "+ x" });
  });

  // Bug: a plain "%2B" wrongly becomes a space instead of "+".
  it("decodes %2B to a literal plus sign", () => {
    expect(parseQuery("a=%2B")).toEqual({ a: "+" });
  });

  // --- Malformed percent-encoding never throws ---

  // Bug: decodeURIComponent throwing on bad input propagates out.
  it("uses the raw token when percent-decoding fails, without throwing", () => {
    expect(parseQuery("a=%zz")).toEqual({ a: "%zz" });
  });

  // Bug: on decode failure the "+"→space replacement is discarded (should be
  // kept — the fallback returns the plus-replaced token).
  it("keeps '+'-to-space replacement when percent-decoding fails", () => {
    expect(parseQuery("a=%zz+b")).toEqual({ a: "%zz b" });
  });

  // Bug: an invalid key encoding throws or drops the pair.
  it("uses the raw key when key percent-decoding fails", () => {
    expect(parseQuery("%zz=1")).toEqual({ "%zz": "1" });
  });

  // Bug: any thrown error at all on truncated escapes.
  it("does not throw on a truncated percent escape", () => {
    expect(() => parseQuery("a=%E2%9C")).not.toThrow();
    expect(parseQuery("a=%E2%9C")).toEqual({ a: "%E2%9C" });
  });
});

